    @Test
    fun `parseSourcesToFileScheme - preserves script and comments`() {
        val input = """
            <!-- VERSION 1.14 -->
            <script>
            var scrollToClozeOnToggle = false
            </script>
            <div id="content">
            <img src="test.jpg">
            </div>
        """.trimIndent()

        val mediaDir = "/media"
        val result = parseSourcesToFileScheme(input, mediaDir)

        // Verify script is preserved
        assertTrue("Script tag should be preserved", result.contains("<script>"))
        assertTrue("Script content should be preserved", result.contains("var scrollToClozeOnToggle = false"))

        // Verify comment is preserved (optional, but good practice if it was stripped before)
        assertTrue("Comment should be preserved", result.contains("<!-- VERSION 1.14 -->"))

        // Verify substitution happened
        assertTrue("Image src should be updated", result.contains("src=\"file:///media/test.jpg\""))
    }
